/**
 * GET /api/admin/qr-pdf
 *
 * Generates an A4 PDF with a 3×5 grid of QR codes — one per table.
 * Each QR encodes http://SHOP_IP:SHOP_PORT/order?table=N.
 * Protected by admin cookie auth.
 */

import { NextRequest } from "next/server";
import path from "path";
import PDFDocument from "pdfkit";
import QRCode from "qrcode";

import { checkAdminCookie } from "@/lib/auth";

// Force Node.js runtime — pdfkit uses Buffer/fs internally
export const runtime = "nodejs";

export async function GET(request: NextRequest) {
  // ── Auth gate ──────────────────────────────────────────────
  const cookieHeader = request.headers.get("cookie");
  if (!checkAdminCookie(cookieHeader)) {
    return Response.json({ error: "Unauthorized" }, { status: 401 });
  }

  // ── Env var validation ─────────────────────────────────────
  const shopIp = process.env.SHOP_IP;
  if (!shopIp) {
    return Response.json(
      { error: "SHOP_IP chưa được cấu hình" },
      { status: 400 },
    );
  }
  const shopPort = process.env.SHOP_PORT || "3000";
  const tableCount = Math.max(0, parseInt(process.env.TABLE_COUNT || "15", 10));

  if (tableCount === 0) {
    return Response.json(
      { error: "TABLE_COUNT phải lớn hơn 0" },
      { status: 400 },
    );
  }

  // ── Font validation ────────────────────────────────────────
  const fontPath = path.join(process.cwd(), "public", "fonts", "Inter.ttf");
  try {
    const fs = await import("fs");
    if (!fs.existsSync(fontPath)) {
      return Response.json(
        { error: "Font file not found" },
        { status: 500 },
      );
    }
  } catch {
    return Response.json(
      { error: "Font file not found" },
      { status: 500 },
    );
  }

  try {
    // ── Generate QR buffers ────────────────────────────────────
    const qrBuffers: Buffer[] = [];
    for (let n = 1; n <= tableCount; n++) {
      const url = `http://${shopIp}:${shopPort}/order?table=${n}`;
      const buf = await QRCode.toBuffer(url, {
        width: 300,
        errorCorrectionLevel: "M",
      });
      qrBuffers.push(buf);
    }

    // ── Build PDF ──────────────────────────────────────────────
    // A4: 595.28 × 841.89 pt, margin 40
    const doc = new PDFDocument({ size: "A4", margin: 40 });
    doc.registerFont("Vietnamese", fontPath);

    // Collect PDF chunks (cannot pipe to Response in Next.js)
    const chunks: Buffer[] = [];
    doc.on("data", (chunk: Buffer) => chunks.push(chunk));
    const pdfReady = new Promise<void>((resolve, reject) => {
      doc.on("end", resolve);
      doc.on("error", reject);
    });

    // ── Layout constants ─────────────────────────────────────
    const pageWidth = 595.28;
    const margin = 40;
    const cols = 3;
    const rows = 5;
    const perPage = cols * rows;
    const availableWidth = pageWidth - margin * 2;
    const colWidth = availableWidth / cols;
    const qrSize = 120;
    const rowHeight = 150;
    const titleHeight = 50;

    // ── Render pages ─────────────────────────────────────────
    const totalPages = Math.ceil(tableCount / perPage);

    for (let page = 0; page < totalPages; page++) {
      if (page > 0) doc.addPage();

      // Page title (only first page gets big title)
      if (page === 0) {
        doc
          .font("Vietnamese")
          .fontSize(20)
          .fillColor("#000000")
          .text("QR Code - TraSua", margin, margin, {
            align: "center",
            width: availableWidth,
          });
      }

      const startY = page === 0 ? margin + titleHeight : margin;
      const startIdx = page * perPage;
      const endIdx = Math.min(startIdx + perPage, tableCount);

      for (let i = startIdx; i < endIdx; i++) {
        const localIdx = i - startIdx;
        const col = localIdx % cols;
        const row = Math.floor(localIdx / cols);

        const cellX = margin + col * colWidth;
        const cellY = startY + row * rowHeight;

        // Center QR in column
        const qrX = cellX + (colWidth - qrSize) / 2;

        // Embed QR image
        doc.image(qrBuffers[i], qrX, cellY, {
          width: qrSize,
          height: qrSize,
        });

        // "Bàn N" label — 14pt, centered below QR
        doc
          .font("Vietnamese")
          .fontSize(14)
          .fillColor("#1a1a1a")
          .text(`Bàn ${i + 1}`, cellX, cellY + qrSize + 4, {
            width: colWidth,
            align: "center",
          });

        // "Quét để đặt món" subtitle — 10pt, lighter
        doc
          .font("Vietnamese")
          .fontSize(10)
          .fillColor("#666666")
          .text("Quét để đặt món", cellX, cellY + qrSize + 20, {
            width: colWidth,
            align: "center",
          });
      }
    }

    doc.end();
    await pdfReady;

    const pdfBuffer = Buffer.concat(chunks);

    return new Response(pdfBuffer, {
      status: 200,
      headers: {
        "Content-Type": "application/pdf",
        "Content-Disposition": 'attachment; filename="trasua-qr-codes.pdf"',
        "Cache-Control": "no-store",
      },
    });
  } catch (err) {
    console.error("[qr-pdf] PDF generation failed:", err);
    return Response.json(
      { error: "PDF generation failed" },
      { status: 500 },
    );
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

/**
 * GET /api/admin/menu
 *
 * Returns ALL menu items (including hidden), ordered by sortOrder.
 * Admin middleware handles authentication.
 */
export async function GET() {
  try {
    const items = await prisma.menuItem.findMany({
      orderBy: { sortOrder: 'asc' },
    })

    console.log(`[GET /api/admin/menu] Returning ${items.length} menu items (including hidden)`)

    return NextResponse.json({ items })
  } catch (error) {
    console.error('[GET /api/admin/menu] Failed to fetch menu items:', error)
    return NextResponse.json(
      { error: 'Không thể tải danh sách món. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * POST /api/admin/menu
 *
 * Creates a new menu item.
 * Required: name (string), price (int > 0), category (DRINK | FOOD).
 * Optional: description (string), sortOrder (int), available (boolean).
 */
export async function POST(request: NextRequest) {
  let body: Record<string, unknown>
  try {
    body = await request.json()
  } catch {
    return NextResponse.json(
      { error: 'Dữ liệu không hợp lệ.' },
      { status: 400 },
    )
  }

  const { name, price, category, description, sortOrder, available } = body

  // --- Validate required fields ---
  if (!name || typeof name !== 'string' || name.trim().length === 0) {
    return NextResponse.json(
      { error: 'Tên món không được để trống' },
      { status: 400 },
    )
  }

  if (typeof price !== 'number' || !Number.isInteger(price) || price <= 0) {
    return NextResponse.json(
      { error: 'Giá phải lớn hơn 0' },
      { status: 400 },
    )
  }

  if (category !== 'DRINK' && category !== 'FOOD') {
    return NextResponse.json(
      { error: 'Danh mục phải là DRINK hoặc FOOD' },
      { status: 400 },
    )
  }

  try {
    const item = await prisma.menuItem.create({
      data: {
        name: name.trim(),
        price,
        category,
        description: typeof description === 'string' ? description.trim() : null,
        sortOrder: typeof sortOrder === 'number' && Number.isInteger(sortOrder) ? sortOrder : 0,
        available: typeof available === 'boolean' ? available : true,
      },
    })

    console.log(`[POST /api/admin/menu] Created menu item #${item.id}: ${item.name}`)

    return NextResponse.json({ item }, { status: 201 })
  } catch (error) {
    console.error('[POST /api/admin/menu] Failed to create menu item:', error)
    return NextResponse.json(
      { error: 'Không thể tạo món mới. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

